// frontend/src/components/UploadForm.js
import React, {useState} from "react";

export default function UploadForm({setResult, setLoading}) {
  const [file, setFile] = useState(null);
  const [error, setError] = useState("");

  const onFileChange = (e) => {
    setFile(e.target.files[0]);
    setError("");
  };

  const onSubmit = async (e) => {
    e.preventDefault();
    if (!file) {
      setError("Please choose an image file.");
      return;
    }

    const form = new FormData();
    form.append("image", file);

    try {
      setLoading(true);
      setResult(null);

      const resp = await fetch("http://127.0.0.1:5000/api/scan", {
        method: "POST",
        body: form
      });

      const data = await resp.json();

      if (!resp.ok) setError(data.error || "Server error");
      else setResult(data);
    } catch (err) {
      setError("Network error: " + err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={onSubmit} style={{marginBottom:"20px", textAlign:"center"}}>
      
      <label style={{
        display:"block",
        marginBottom:"10px",
        fontSize:"16px",
        fontWeight:"600",
        color:"#2563eb"
      }}>
        Upload Image
      </label>

      <input 
        type="file" 
        accept="image/*"
        onChange={onFileChange}
        style={{
          padding:"10px",
          border:"2px dashed #2563eb",
          borderRadius:"8px",
          width:"100%",
          cursor:"pointer",
          background:"#eef4ff"
        }}
      />

      <button
        type="submit"
        style={{
          marginTop:"15px",
          background:"#2563eb",
          padding:"10px 25px",
          border:"none",
          borderRadius:"8px",
          fontSize:"16px",
          fontWeight:"600",
          color:"white",
          cursor:"pointer"
        }}
      >
        Scan Now
      </button>

      {error && <div style={{color:"red", marginTop:"8px"}}>{error}</div>}
    </form>
  );
}
